Use cc.TransitionFade with cc.director.replaceScene:
var newScene = new GameScene();
var transition = cc.TransitionFade.create(1.5, newScene, cc.color(0, 0, 0));
cc.director.replaceScene(transition);

Other transition types:
- cc.TransitionSlideInR.create(duration, scene) — slide from right
- cc.TransitionFlipX.create(duration, scene) — flip horizontally
- cc.TransitionCrossFade.create(duration, scene) — cross-fade
- cc.TransitionPageTurn.create(duration, scene, backwards) — page turn effect

cc.Director.runScene() should only be used for the very first scene. For subsequent scenes, use:
- cc.director.replaceScene(newScene) — replaces current scene
- cc.director.pushScene(newScene) — pushes onto scene stack
Also note the API difference: use cc.director (lowercase singleton) not cc.Director (the class).
Correct usage: cc.director.replaceScene(new MyScene());
If using transitions: cc.director.replaceScene(cc.TransitionFade.create(1.0, new MyScene()));

Create a sp.SkeletonAnimation, play an animation, and set a completion listener:
var skeleton = sp.SkeletonAnimation.create('spine/hero.json', 'spine/hero.atlas');
skeleton.setPosition(cc.p(240, 160));
parent.addChild(skeleton);

// Play 'run' animation on track 0, looping
skeleton.setAnimation(0, 'run', true);

// Listen for animation events
skeleton.setAnimationListener(this, function(skeleton, trackIndex, type, event, loopCount) {
    if (type === sp.AnimationEventType.END) {
        cc.log('Animation ended on track ' + trackIndex);
    } else if (type === sp.AnimationEventType.COMPLETE) {
        cc.log('Animation loop completed: ' + loopCount);
    }
});

Create a label and use this.schedule to update it every second:
var timeLeft = 60;
var timerLabel = cc.Label.createWithSystemFont(timeLeft.toString(), 'Arial', 36);
timerLabel.setPosition(cc.p(240, 400));
this.addChild(timerLabel);

this.schedule(function(dt) {
    timeLeft--;
    timerLabel.setString(timeLeft.toString());
    if (timeLeft <= 0) {
        this.unschedule(arguments.callee);
        cc.log('Time is up!');
    }
}.bind(this), 1.0);

Use the node's scheduler via the director, not cc.scheduler directly:
Correct: this.schedule(callback, interval, repeat, delay)
Or: cc.director.getScheduler().schedule(callback, target, interval, repeat, delay, paused)

Common mistakes:
- this.schedule must be called on a cc.Node subclass (inside a layer/scene)
- The callback must be a function, not a string
- Make sure 'this' context is correct — use .bind(this) if needed

Example:
this.schedule(function(dt) {
    // runs every 0.5 seconds
}, 0.5);

Common reasons for touch events not firing:
1. The node must be added to the scene (not just created)
2. The listener must be registered: cc.eventManager.addListener(listener, node)
3. Check swallowTouches: if a higher-priority listener swallows touches, lower ones won't fire
4. The node's contentSize must be set (for cc.EventListener.TOUCH_ONE_BY_ONE, onTouchBegan must return true)
5. Ensure the node is visible and not scaled to 0
Example:
var listener = cc.EventListener.create({
    event: cc.EventListener.TOUCH_ONE_BY_ONE,
    onTouchBegan: function(touch, event) { return true; },
    onTouchMoved: function(touch, event) { /* handle */ }
});
cc.eventManager.addListener(listener, myNode);

cc.sequence runs actions one after another (sequentially), while cc.spawn runs actions all at the same time (in parallel).

- cc.sequence(action1, action2): action2 starts only after action1 completes
- cc.spawn(action1, action2): both actions start and run simultaneously

Example:
// Sequential: move right, then move up
node.runAction(cc.sequence(cc.moveBy(1, cc.p(100, 0)), cc.moveBy(1, cc.p(0, 100))));

// Parallel: move right AND fade out at the same time
node.runAction(cc.spawn(cc.moveBy(1, cc.p(100, 0)), cc.fadeOut(1)));

Use cc.DrawNode to draw a filled rectangle representing the health bar:
var maxHP = 100;
var currentHP = 75;
var barWidth = 200;
var barHeight = 20;

var bgBar = new cc.DrawNode();
var hpBar = new cc.DrawNode();
bgBar.setPosition(cc.p(120, 440));
hpBar.setPosition(cc.p(120, 440));
this.addChild(bgBar);
this.addChild(hpBar);

function updateHP(hp) {
    currentHP = Math.max(0, Math.min(hp, maxHP));
    var ratio = currentHP / maxHP;
    bgBar.clear();
    bgBar.drawRect(cc.p(0, 0), cc.p(barWidth, barHeight), cc.color(80, 80, 80), 1, cc.color(0, 0, 0));
    hpBar.clear();
    var color = ratio > 0.5 ? cc.color(0, 200, 0) : (ratio > 0.25 ? cc.color(255, 165, 0) : cc.color(200, 0, 0));
    hpBar.drawRect(cc.p(0, 0), cc.p(barWidth * ratio, barHeight), color, 0, color);
}
updateHP(currentHP);

Use cc.bezierTo for the path and cc.rotateBy for rotation, running them in parallel with cc.spawn:
var sprite = new cc.Sprite('arrow.png');
sprite.setPosition(cc.p(50, 50));
parent.addChild(sprite);

var bezierConfig = [
    cc.p(150, 300),  // control point 1
    cc.p(350, 300),  // control point 2
    cc.p(400, 50)    // end point
];
var bezierAction = cc.bezierTo(2.0, bezierConfig);
var rotate = cc.rotateBy(2.0, 360);
sprite.runAction(cc.spawn(bezierAction, rotate));

Create the sprite, then run a sequence of moveTo and fadeOut actions:
var sprite = new cc.Sprite('image.png');
sprite.setPosition(cc.p(100, 100));
parent.addChild(sprite);

var move = cc.moveTo(1.0, cc.p(300, 400));
var fade = cc.fadeOut(2.0);
sprite.runAction(cc.sequence(move, fade));

cc.Sequence requires cc.sequence() (lowercase) as a helper function, or you need to use cc.Sequence.create(). The correct usage is:
node.runAction(cc.sequence(action1, action2));
Alternatively: node.runAction(cc.Sequence.create(action1, action2));
Using cc.Sequence() directly as a constructor without create() may silently fail or only execute the first action.

Use cc.sys.localStorage for persistent key-value storage:
// Save game progress
var saveData = {
    level: 5,
    score: 12500,
    lives: 3
};
cc.sys.localStorage.setItem('gameProgress', JSON.stringify(saveData));

// Load game progress
var loaded = cc.sys.localStorage.getItem('gameProgress');
if (loaded) {
    var data = JSON.parse(loaded);
    cc.log('Level: ' + data.level + ', Score: ' + data.score);
} else {
    cc.log('No saved progress found');
}

// Remove saved data
cc.sys.localStorage.removeItem('gameProgress');

Create a ccui.Button and add a touch event listener that plays the sound:
var button = new ccui.Button('btn_normal.png', 'btn_pressed.png');
button.setPosition(cc.p(240, 160));
parent.addChild(button);

button.addTouchEventListener(function(sender, type) {
    if (type === ccui.Widget.TOUCH_ENDED) {
        cc.audioEngine.playEffect('click.mp3');
    }
});

No, cc.Sprite.create() returns a sprite but does not have an addTo() method that can be chained directly. The correct approach is:
var sprite = new cc.Sprite('image.png');
parent.addChild(sprite);
In Cocos2d-x JS, you typically use `new cc.Sprite(filename)` (constructor) rather than `cc.Sprite.create()`, and `addChild` is called on the parent node.

Add a touch listener to the layer and create a particle system at the touch location:
var listener = cc.EventListener.create({
    event: cc.EventListener.TOUCH_ONE_BY_ONE,
    onTouchBegan: function(touch, event) {
        var pos = touch.getLocation();
        var particle = new cc.ParticleSystem('particles/explosion.plist');
        particle.setPosition(pos);
        particle.setAutoRemoveOnFinish(true);
        this.addChild(particle);
        return true;
    }.bind(this)
});
cc.eventManager.addListener(listener, this);

Create a ScrollView, add labels as children, and set the inner container size:
var scrollView = new ccui.ScrollView();
scrollView.setContentSize(cc.size(300, 400));
scrollView.setDirection(ccui.ScrollView.DIR_VERTICAL);
scrollView.setBounceEnabled(true);
parent.addChild(scrollView);

var items = ['Item 1', 'Item 2', 'Item 3', 'Item 4', 'Item 5'];
var yOffset = items.length * 50;
scrollView.setInnerContainerSize(cc.size(300, yOffset));

for (var i = 0; i < items.length; i++) {
    var label = cc.Label.createWithSystemFont(items[i], 'Arial', 20);
    label.setPosition(cc.p(150, yOffset - (i * 50) - 25));
    scrollView.addChild(label);
}
